'use strict';function authLogin(){const form=document.getElementById('login-form');const data=new FormData(form);$.ajax({type:'POST',url:'/account/login',data:data,processData:false,contentType:false,}).done(function(res){document.getElementById('login-error').textContent='';document.getElementById('user-name').textContent=res.first_name;document.body.classList.add('authenticated');form.reset();}).fail(function(xhr){const errors=xhr.responseJSON||{};const first=Object.values(errors)[0];document.getElementById('login-error').textContent=(first&&first[0])||'Login failed';});}
function authLogout(){$.ajax({type:'POST',url:'/account/logout',}).done(function(){window.location.href='/';}).fail(ajaxFailure);}'use strict';$.ajaxSetup({beforeSend:function(xhr,settings){if(!/^(GET|HEAD|OPTIONS|TRACE)$/i.test(settings.type)){xhr.setRequestHeader('X-CSRFToken',$('meta[name="csrf-token"]').attr('content'));}}});const postJson=(url,json)=>{return $.ajax({type:"POST",url:url,contentType:"application/json",data:JSON.stringify(json)});};const ajaxFailure=(data,status,error)=>{console.error('Ajax Error:',error,data.responseText);alert(`Error: ${error}\n${data.responseText}`);};